::: {.cell}
<style type="text/css">
.embed-container {
    position: relative;
    padding-bottom: 129%;
    height: 0;
    overflow: hidden;
    max-width: 100%;
    border: 1px solid #ddd; /* 给 PDF 加上一层淡淡的边框，更有质感 */
}
.embed-container iframe,
.embed-container object,
.embed-container embed {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
}

/* 在这里强制声明按钮样式，彻底解决样式丢失问题 */
.btn-lux-black {
    background-color: #1A1A1A !important;
    color: #F5F5F1 !important;
    border: none !important;
    padding: 15px 40px !important;
    font-family: "Inter", "Helvetica Neue", sans-serif;
    text-transform: uppercase;
    letter-spacing: 2px;
    font-weight: 600;
    font-size: 0.95rem;
    text-decoration: none !important;
    display: inline-block;
    transition: all 0.3s ease;
}

.btn-lux-black:hover {
    background-color: #9E2A2B !important; /* 鼠标悬停变成你的专属朱砂红 */
    color: #F5F5F1 !important;
}
</style>
:::


<div class="embed-container">
  <iframe src="cv.pdf#toolbar=0" style="border: none; width: 100%;"></iframe>
</div>

<div style="text-align: center; margin-top: 50px; margin-bottom: 60px;">
  <a class="btn-lux-black" href="cv.pdf" role="button" target="_blank">
    <i class="fa-solid fa-file-arrow-down"></i>&ensp;DOWNLOAD CURRENT CV
  </a>
</div>
